-- Basic transaction control
BEGIN TRANSACTION;

    INSERT INTO Accounts (AccountId, Balance) VALUES (1, 1000.00);
    UPDATE Accounts SET Balance = Balance - 100.00 WHERE AccountId = 1;

    -- Check for errors before committing
    IF @@ERROR <> 0
    BEGIN
        ROLLBACK TRANSACTION;
        RETURN;
    END

COMMIT TRANSACTION;

-- Savepoint (nested transaction) example
BEGIN TRANSACTION;

    INSERT INTO Orders (OrderId, CustomerId, Amount) VALUES (101, 5, 250.00);

    SAVE TRANSACTION SavePoint1;

    UPDATE Inventory SET Quantity = Quantity - 1 WHERE ProductId = 42;

    -- If inventory update fails, rollback only to the savepoint
    IF @@ERROR <> 0
    BEGIN
        ROLLBACK TRANSACTION SavePoint1;
    END

COMMIT TRANSACTION;

