-- Basic transaction control
BEGIN;

    INSERT INTO accounts (account_id, balance) VALUES (1, 1000.00);
    UPDATE accounts SET balance = balance - 100.00 WHERE account_id = 1;

COMMIT;

-- Rollback example
BEGIN;

    INSERT INTO accounts (account_id, balance) VALUES (2, 500.00);

    -- Something went wrong, undo everything
    ROLLBACK;

-- Savepoint example
BEGIN;

    INSERT INTO orders (order_id, customer_id, amount) VALUES (101, 5, 250.00);

    SAVEPOINT savepoint1;

    UPDATE inventory SET quantity = quantity - 1 WHERE product_id = 42;

    -- If inventory update fails, rollback only to the savepoint
    -- ROLLBACK TO SAVEPOINT savepoint1;

    -- Release savepoint when no longer needed (optional)
    RELEASE SAVEPOINT savepoint1;

COMMIT;

