-- Set isolation level for the current session
SET TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;

-- Dirty read: can see uncommitted changes from other transactions
BEGIN TRANSACTION;
    SELECT AccountId, Balance FROM Accounts;
COMMIT TRANSACTION;

-- Default isolation level (READ COMMITTED)
SET TRANSACTION ISOLATION LEVEL READ COMMITTED;

-- REPEATABLE READ: prevents non-repeatable reads
SET TRANSACTION ISOLATION LEVEL REPEATABLE READ;
BEGIN TRANSACTION;
    SELECT AccountId, Balance FROM Accounts WHERE AccountId = 1;
    -- Re-reading same row will return same data
    SELECT AccountId, Balance FROM Accounts WHERE AccountId = 1;
COMMIT TRANSACTION;

-- SERIALIZABLE: highest isolation, prevents phantom reads
SET TRANSACTION ISOLATION LEVEL SERIALIZABLE;

-- SNAPSHOT: row versioning, no blocking readers
-- Requires database-level setting first:
-- ALTER DATABASE SQLToPostgres SET ALLOW_SNAPSHOT_ISOLATION ON;
SET TRANSACTION ISOLATION LEVEL SNAPSHOT;
BEGIN TRANSACTION;
    SELECT AccountId, Balance FROM Accounts;
COMMIT TRANSACTION;

-- Check current session isolation level
SELECT
    CASE transaction_isolation_level
        WHEN 1 THEN 'READ UNCOMMITTED'
        WHEN 2 THEN 'READ COMMITTED'
        WHEN 3 THEN 'REPEATABLE READ'
        WHEN 4 THEN 'SERIALIZABLE'
        WHEN 5 THEN 'SNAPSHOT'
        ELSE 'UNKNOWN'
    END AS IsolationLevel
FROM sys.dm_exec_sessions
WHERE session_id = @@SPID;

