-- Set isolation level per transaction
BEGIN TRANSACTION ISOLATION LEVEL READ UNCOMMITTED;
-- Note: PostgreSQL treats READ UNCOMMITTED as READ COMMITTED
-- Dirty reads are impossible due to MVCC architecture
    SELECT account_id, balance FROM accounts;
COMMIT;

-- READ COMMITTED (default) - no dirty reads
BEGIN TRANSACTION ISOLATION LEVEL READ COMMITTED;
    SELECT account_id, balance FROM accounts WHERE account_id = 1;
COMMIT;

-- REPEATABLE READ - prevents non-repeatable reads and phantom reads
BEGIN TRANSACTION ISOLATION LEVEL REPEATABLE READ;
    SELECT account_id, balance FROM accounts WHERE account_id = 1;
    -- Will see a consistent snapshot from transaction start
    SELECT account_id, balance FROM accounts WHERE account_id = 1;
COMMIT;

-- SERIALIZABLE - full serializability via SSI (Serializable Snapshot Isolation)
BEGIN TRANSACTION ISOLATION LEVEL SERIALIZABLE;
    SELECT account_id, balance FROM accounts;
COMMIT;

-- Set default isolation level for the session
SET default_transaction_isolation TO 'repeatable read';

-- Check current isolation level
SHOW transaction_isolation;

-- Reset to default
SET default_transaction_isolation TO 'read committed';

