-- NOLOCK: dirty read, no shared lock acquired
-- Use with caution: can return uncommitted or phantom data
SELECT AccountId, Balance
FROM Accounts WITH (NOLOCK);

-- UPDLOCK: acquire update lock to prevent deadlocks
-- Use when reading before updating in same transaction
BEGIN TRANSACTION;
    SELECT AccountId, Balance
    FROM Accounts WITH (UPDLOCK)
    WHERE AccountId = 1;

    UPDATE Accounts SET Balance = Balance - 100.00
    WHERE AccountId = 1;
COMMIT TRANSACTION;

-- HOLDLOCK: hold shared lock until transaction ends (SERIALIZABLE)
BEGIN TRANSACTION;
    SELECT AccountId, Balance
    FROM Accounts WITH (HOLDLOCK)
    WHERE AccountId = 1;
    -- Shared lock held until COMMIT/ROLLBACK
COMMIT TRANSACTION;

-- ROWLOCK: hint to prefer row-level locks over page/table locks
BEGIN TRANSACTION;
    UPDATE Accounts WITH (ROWLOCK)
    SET Balance = Balance + 10.00
    WHERE AccountId = 1;
COMMIT TRANSACTION;

-- TABLOCK + HOLDLOCK: full table lock for the transaction
BEGIN TRANSACTION;
    SELECT COUNT(*) FROM Accounts WITH (TABLOCK, HOLDLOCK);
COMMIT TRANSACTION;

