-- FOR UPDATE: exclusive row lock (equivalent to UPDLOCK)
-- Prevents other transactions from locking or modifying these rows
BEGIN;
    SELECT account_id, balance
    FROM accounts
    WHERE account_id = 1
    FOR UPDATE;

    UPDATE accounts SET balance = balance - 100.00
    WHERE account_id = 1;
COMMIT;

-- FOR SHARE: shared lock — prevents modification but allows other shared locks
BEGIN;
    SELECT account_id, balance
    FROM accounts
    WHERE account_id = 1
    FOR SHARE;
COMMIT;

-- FOR NO KEY UPDATE: weaker exclusive lock
-- Allows other transactions to acquire FOR KEY SHARE locks (for FK checks)
BEGIN;
    SELECT account_id, balance
    FROM accounts
    WHERE account_id = 1
    FOR NO KEY UPDATE;
COMMIT;

-- FOR UPDATE SKIP LOCKED: skip rows locked by other transactions
-- Useful for queue processing patterns
BEGIN;
    SELECT account_id, balance
    FROM accounts
    WHERE account_id = 1
    FOR UPDATE SKIP LOCKED;
COMMIT;

-- FOR UPDATE NOWAIT: fail immediately if rows are locked (no waiting)
BEGIN;
    SELECT account_id, balance
    FROM accounts
    WHERE account_id = 1
    FOR UPDATE NOWAIT;
COMMIT;

-- Note: No direct NOLOCK equivalent
-- PostgreSQL's default READ COMMITTED uses MVCC
-- Readers never see uncommitted data and never block writers

